function evaluateTemplateFormula(template, data) {
  const match = template.match(/^\s*\{\{\s*(.*?)\s*\}\}\s*$/);
  if (!match) {
    throw new Error("Invalid template expression");
  }

  const expr = match[1];

  if (!/^[\w\s.+\-*/()%]+$/.test(expr)) {
    throw new Error("Unsupported characters in expression");
  }

  const tokens = expr.match(/\d+(\.\d+)?|[A-Za-z_]\w*|[()+\-*/%]/g);
  if (!tokens) {
    throw new Error("Unable to parse expression");
  }

  let i = 0;

  function peek() {
    return tokens[i];
  }

  function consume() {
    return tokens[i++];
  }

  function parsePrimary() {
    const token = consume();

    if (!token) {
      throw new Error("Unexpected end of expression");
    }

    if (/^\d/.test(token)) {
      return Number(token);
    }

    if (/^[A-Za-z_]\w*$/.test(token)) {
      if (!(token in data) || typeof data[token] !== "number") {
        throw new Error(`Unknown or non-numeric field: ${token}`);
      }
      return data[token];
    }

    if (token === "(") {
      const value = parseExpression();
      if (consume() !== ")") {
        throw new Error("Missing closing parenthesis");
      }
      return value;
    }

    if (token === "-") {
      return -parsePrimary();
    }

    throw new Error(`Unexpected token: ${token}`);
  }

  function parseTerm() {
    let value = parsePrimary();

    while (peek() === "*" || peek() === "/" || peek() === "%") {
      const op = consume();
      const right = parsePrimary();

      if (op === "*") value *= right;
      if (op === "/") value /= right;
      if (op === "%") value %= right;
    }

    return value;
  }

  function parseExpression() {
    let value = parseTerm();

    while (peek() === "+" || peek() === "-") {
      const op = consume();
      const right = parseTerm();

      if (op === "+") value += right;
      if (op === "-") value -= right;
    }

    return value;
  }

  const result = parseExpression();

  if (i !== tokens.length) {
    throw new Error("Unexpected trailing tokens");
  }

  return result;
}

