export function evaluateTemplateFormula(template, data) {
  const match = template.match(/^\s*\{\{([\s\S]+)\}\}\s*$/);
  if (!match) {
    throw new Error("Template must be a single {{...}} expression");
  }

  const expr = match[1].trim();
  return evaluateExpression(expr, data);
}

function evaluateExpression(expr, data) {
  const tokens = tokenize(expr);
  const rpn = toRpn(tokens);
  return evalRpn(rpn, data);
}

function tokenize(expr) {
  const tokens = [];
  let i = 0;

  while (i < expr.length) {
    const ch = expr[i];

    if (/\s/.test(ch)) {
      i++;
      continue;
    }

    if (/[0-9.]/.test(ch)) {
      let j = i;
      while (j < expr.length && /[0-9.]/.test(expr[j])) j++;
      tokens.push({ type: "number", value: Number(expr.slice(i, j)) });
      i = j;
      continue;
    }

    if (/[a-zA-Z_$]/.test(ch)) {
      let j = i;
      while (j < expr.length && /[a-zA-Z0-9_.$]/.test(expr[j])) j++;
      tokens.push({ type: "identifier", value: expr.slice(i, j) });
      i = j;
      continue;
    }

    if ("+-*/()".includes(ch)) {
      tokens.push({ type: "operator", value: ch });
      i++;
      continue;
    }

    throw new Error(`Unexpected character: ${ch}`);
  }

  return tokens;
}

function toRpn(tokens) {
  const output = [];
  const ops = [];
  const precedence = { "+": 1, "-": 1, "*": 2, "/": 2 };

  for (const token of tokens) {
    if (token.type === "number" || token.type === "identifier") {
      output.push(token);
      continue;
    }

    if (token.value === "(") {
      ops.push(token);
      continue;
    }

    if (token.value === ")") {
      while (ops.length && ops[ops.length - 1].value !== "(") {
        output.push(ops.pop());
      }
      if (!ops.length) throw new Error("Mismatched parentheses");
      ops.pop();
      continue;
    }

    while (
      ops.length &&
      ops[ops.length - 1].value !== "(" &&
      precedence[ops[ops.length - 1].value] >= precedence[token.value]
    ) {
      output.push(ops.pop());
    }

    ops.push(token);
  }

  while (ops.length) {
    const op = ops.pop();
    if (op.value === "(") throw new Error("Mismatched parentheses");
    output.push(op);
  }

  return output;
}

function evalRpn(rpn, data) {
  const stack = [];

  for (const token of rpn) {
    if (token.type === "number") {
      stack.push(token.value);
      continue;
    }

    if (token.type === "identifier") {
      stack.push(resolvePath(data, token.value));
      continue;
    }

    const b = stack.pop();
    const a = stack.pop();

    switch (token.value) {
      case "+":
        stack.push(a + b);
        break;
      case "-":
        stack.push(a - b);
        break;
      case "*":
        stack.push(a * b);
        break;
      case "/":
        stack.push(a / b);
        break;
      default:
        throw new Error(`Unsupported operator: ${token.value}`);
    }
  }

  if (stack.length !== 1) {
    throw new Error("Invalid expression");
  }

  return stack[0];
}

function resolvePath(obj, path) {
  return path.split(".").reduce((acc, key) => {
    if (acc == null || !Object.prototype.hasOwnProperty.call(acc, key)) {
      throw new Error(`Unknown field: ${path}`);
    }
    return acc[key];
  }, obj);
}

