  const match = template.match(/^\s*\{\{(.+)\}\}\s*$/);
  if (!match) {
    throw new Error("Template must be in the form {{ expression }}");
  }

  const expression = match[1].trim();
  return evaluateExpression(expression, context);
}

function evaluateExpression(expression, context) {
  const tokens = tokenize(expression);
  let pos = 0;

  function peek() {
    return tokens[pos];
  }

  function consume(type) {
    const token = tokens[pos];
    if (!token || (type && token.type !== type)) {
      throw new Error(`Unexpected token: ${token ? token.value : "end of input"}`);
    }
    pos++;
    return token;
  }

  function parseExpression() {
    let node = parseTerm();
    while (peek() && (peek().value === "+" || peek().value === "-")) {
      const op = consume().value;
      const rhs = parseTerm();
      node = op === "+" ? node + rhs : node - rhs;
    }
    return node;
  }

  function parseTerm() {
    let node = parseFactor();
    while (peek() && (peek().value === "*" || peek().value === "/")) {
      const op = consume().value;
      const rhs = parseFactor();
      node = op === "*" ? node * rhs : node / rhs;
    }
    return node;
  }

  function parseFactor() {
    const token = peek();

    if (!token) {
      throw new Error("Unexpected end of expression");
    }

    if (token.type === "number") {
      consume("number");
      return token.value;
    }

    if (token.type === "identifier") {
      consume("identifier");
      if (!(token.value in context)) {
        throw new Error(`Unknown variable: ${token.value}`);
      }
      const value = context[token.value];
      if (typeof value !== "number") {
        throw new Error(`Variable ${token.value} must be a number`);
      }
      return value;
    }

    if (token.value === "(") {
      consume("symbol");
      const value = parseExpression();
      if (!peek() || peek().value !== ")") {
        throw new Error("Missing closing parenthesis");
      }
      consume("symbol");
      return value;
    }

