        throw new Error("Invalid number");
      }
      tokens.push({ type: "number", value });
      continue;
    }

    if (/[A-Za-z_]/.test(ch)) {
      let start = i;
      i++;
      while (i < input.length && /[A-Za-z0-9_]/.test(input[i])) {
        i++;
