      tokens.push({ type: "identifier", value: input.slice(start, i) });
      continue;
    }

    const singleCharTokens = {
      "+": "plus",
      "-": "minus",
      "*": "multiply",
      "/": "divide",
      "(": "lparen",
      ")": "rparen",
    };

    const type = singleCharTokens[ch];
    if (!type) {
      throw new Error(`Unsupported character: ${ch}`);
    }

    tokens.push({ type, value: ch });
    i++;
